async function* processResults(rawStream: AsyncIterable<RawMatch>) {
  const seen = new Set<string>();
  const pending: Promise<SearchResult>[] = [];

  for await (const raw of rawStream) {
    const key = `${raw.projectId}/${raw.sessionId}`;

    // Dedup MUST be synchronous — before any await
    if (seen.has(key)) continue;
    seen.add(key);

    // Queue enrichment but yield results in order
    const enriched = await enrichResult(raw);
    yield { type: 'result', data: enriched };
  }
}

